var body = $input.first().json.body || $input.first().json;
var tenantId = body.tenantId;
var limit = body.limit || 50;
var offset = body.offset || 0;
var status = body.status;

var query = `SELECT id, tenant_id AS \"tenantId\", nom, sujet, template_id AS \"templateId\", list_id AS \"listId\", expediteur_nom AS \"expediteurNom\", expediteur_email AS \"expediteurEmail\", status, scheduled_at AS \"scheduledAt\", sent_at AS \"sentAt\", total_envoyes AS \"totalEnvoyes\", total_ouverts AS \"totalOuverts\", total_cliques AS \"totalCliques\", total_bounces AS \"totalBounces\", total_desabonnes AS \"totalDesabonnes\", created_at AS \"createdAt\" FROM email_campaigns WHERE tenant_id = $1`;

var countQuery = `SELECT COUNT(*) as total FROM email_campaigns WHERE tenant_id = $1`;
var params = [tenantId];

if (status) {
  query += ` AND status = $2`;
  countQuery += ` AND status = $2`;
  params.push(status);
}

query += ` ORDER BY created_at DESC LIMIT $${params.length + 1} OFFSET $${params.length + 2}`;
params.push(limit, offset);

countQuery += ` ORDER BY created_at DESC`;

return {
  query: query,
  countQuery: countQuery,
  params: params,
  limit: limit,
  offset: offset
};

var campaigns = $node["Postgres Query"].json;
var countResult = $node["Postgres Count"].json;
var total = countResult[0]?.total || 0;
var limit = $node["Parser Code"].json.limit;
var offset = $node["Parser Code"].json.offset;

return {
  campaigns: campaigns,
  total: total,
  limit: limit,
  offset: offset
};
